var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라, 잠깐 나와 봐. 손님이야.","JPN":"ラウラ、ちょっと来て。お客さんだわ。","ENG":"Laura, come on out here for a second. We've got a customer.","TWN":"蘿拉，妳出來一下，有客人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"마감 시간에 웬 손님이람. 커피 한 잔 주고 돌려보내.","JPN":"閉店時間に客だと？　コーヒー一杯渡して送り返せ。","ENG":"But it's nearly closing time. Just give them a cup of coffee on the house and kick them out.","TWN":"都到要下班了怎麼還有客人。給杯咖啡打發他回去吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아쉽지만 다른 용건이야.","JPN":"残念だけど、コーヒーを飲みに来たんじゃないわ。","ENG":"Unfortunately she's here for another reason.","TWN":"很可惜，是有別的事情。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"전단지 돌리는 마녀에게 여기 오면 소원을 이뤄 준다는 얘기를 들었다던데?","JPN":"チラシを配っていた魔女に、ここに来ると願い事を叶えてくれるって聞いたそうよ。","ENG":"She said a witch gave her a pamphlet saying we can grant her wish here.","TWN":"她說發傳單的魔女告訴她，只要來到店裡就能實現願望？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......또 그 바보 소행이구나. 정말 지치지도 않나 보네.","JPN":"……またあのバカの仕業か。あいつも懲りないものだ。","ENG":"Ugh, it's that idiot again... She never gives up, does she?","TWN":"……又是那個笨蛋做的好事啊，她真是不會膩耶。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 아까 그 사람! 바로 와 줬어! 아자! 마케팅의 성공!","JPN":"あっ！　さっきの人ね！　すぐに来てくれたんだ！　やった！　客引き成功！","ENG":"Oh! It's her from before! She really came! Woohoo! My marketing worked!","TWN":"啊！剛才那個人！這麼快就來啦！耶！推銷成功！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"플루토. 마구 할퀴어 버려.","JPN":"プルートー。引っ掻いてやれ。","ENG":"Pluto. Tear up her face.","TWN":"布魯托，抓爛她的臉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아야야야! 미안, 플루토! 정어리 사 줄게! 정어리!","JPN":"あいたたた！　ごめん、プルートー！　イワシ買ってあげるから！　イワシ！","ENG":"Ow! I'm sorry, Pluto! I'll buy you a can of tuna! Tuna!","TWN":"啊啊啊啊！抱歉，布魯托！我會給你買沙丁魚的！沙丁魚！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"야박하게 왜 그래. 지점 낸 뒤로 기념할 만한 첫 손님이잖아.","JPN":"薄情なことしないで。支店を出してからの、記念すべき初めてのお客さんでしょ。","ENG":"Don't be so hard on her. It's our first customer after opening this branch.","TWN":"不要這麼無情嘛，這可是分店開張後值得紀念的第一位客人耶。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"정말 여기서 내 소원을 이뤄 줄 수 있어?","JPN":"本当にここで私の願い事を叶えてもらえるの？","ENG":"Can you guys really grant my wish here?","TWN":"這裡真的可以實現我的願望嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......그래. 같은 카운터 능력이라도 어떻게 쓰느냐에 따라 할 수 있는 일이 다르거든.","JPN":"……そうだ。同じカウンターでも能力をどう使うかによって、できることが違うからな。","ENG":"Yeah. There's all sorts of ways Counters can use their abilities.","TWN":"……沒錯。但就算是同樣的制裁者能力，也會因不同的使用方法獲得不同的結果。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"물론 마녀에게 소원을 빌려면 대가가 필요해.","JPN":"もちろん、魔女に願い事をするためには対価が必要だ。","ENG":"Of course, you'll have to pay a price if you want a witch to grant you your wish.","TWN":"當然，向魔女許願是需要代價的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그리고 난 네가 뭘 주든 절대 안 받을 거야. 메롱.","JPN":"それに妾は汝に何を渡されようが、絶対受け取らない。ベーだ。","ENG":"And I won't take any payment from you, no matter what. So get lost.","TWN":"還有，無論妳給我什麼我都不會收下的。吐舌頭～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"심술 궂어. 마귀 할멈.","JPN":"意地悪の鬼婆ね。","ENG":"You're mean. A mean old witch.","TWN":"壞心眼，老巫婆。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그러는 넌 급체 걸린 백설공주니?","JPN":"そういう汝こそ、急に胃もたれでもした白雪姫か？","ENG":"Think that makes you Snow White or something?","TWN":"那妳就是消化不良的白雪公主囉？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아, 어디서 봤나 했더니 하트베리였구나?","JPN":"あ、見覚えがあると思ったらハートベリーの子よね？","ENG":"Oh, I knew I've seen you from somewhere! You're HRT Berry, right?","TWN":"啊，我說怎麼這麼眼熟，這不是愛心莓果嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"가은이 맞지? 얼음공주!","JPN":"ユキでしょ？　氷姫の！","ENG":"Gaeun, right? The Icy Princess!","TWN":"嘉恩對吧？冰雪公主！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......짜-잔. 가은이에요.","JPN":"……じゃーん。ユキです。","ENG":"... Tah-dah. Gaeun here.","TWN":"……鏘—鏘，我是嘉恩。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗, 영상이랑 똑같이 어색한 리액션이네.","JPN":"ふふっ、映像と同じでぎこちないリアクションなのね。","ENG":"Hah hah, you're as awkward in person as you are in the videos.","TWN":"呵呵，這生澀的反應跟影片裡一模一樣啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이렇게 만날 줄은 몰랐어. 혹시 언니가 기념으로 사인 좀 받아도 될까?","JPN":"こんな所で会えるなんてね。お姉さんが記念にサインをもらってもいいかな？","ENG":"I never thought I'd get to meet you like this. Could I get an autograph?","TWN":"沒想到會以這種方式見面，姐姐可以向妳要個簽名作紀念嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"네. 기꺼이.","JPN":"はい。もちろんです。","ENG":"Sure. Gladly.","TWN":"好啊，我很樂意。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 이를 어쩌나♪ 대가를 받아 버렸어, 라우라♪","JPN":"あら、どうしよう♪　対価を受け取ってしまったわ、ラウラ♪","ENG":"Oh my. What are we going to do? ♪ I've accepted her payment, Laura! ♪","TWN":"唉呀。這下怎麼辦呢♪拿到代價啦，蘿拉♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이제 진지하게 상담을 들어 줄 수밖에 없겠는데?","JPN":"これでもう真剣に相談に乗るしかなくなったわね。","ENG":"I guess we have no choice but to hear her out now!","TWN":"這下妳只能認真聽她說了吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"성공했습니다. 아자.","JPN":"成功しました。よっしゃぁ。","ENG":"Success. Woohoo.","TWN":"成功了，耶。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흥. 바보들.","JPN":"ふん。愚か者どもが。","ENG":"Hmpf, you're a bunch of idiots.","TWN":"哼，一群笨蛋。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래서, 예전에 헤어진 사람을 다시 만났는데 널 몰라볼 것 같아서 걱정된다고?","JPN":"それで、前に別れた人と再会したけど、汝のことに気付いてもらえなさそうで心配だと？","ENG":"So you finally found the person you've been looking for, but this person doesn't seem to recognize you?","TWN":"也就是說，妳遇到了以前和妳分手的人，但他好像不認識妳，所以妳很擔心？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"왠지 낭만적이다~ 언제부터 만나고 싶었어요?","JPN":"ロマンチックな話だね～、いつから会いたかったんですか？","ENG":"Aww... How romantic! How long have you been longing to see this person again?","TWN":"總覺得好浪漫哟～妳從什麼時候開始想要見他的啊？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"어릴 때부터 계속.","JPN":"子供の頃からずっと。","ENG":"Ever since when I was a child.","TWN":"從小時候開始一直。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"난 그런 얘긴 잘 모르겠고, 뭐하는 사람이야? 강해?","JPN":"そんなことより、何する人なの？　強い？","ENG":"Yeah, I couldn't care less about that sappy nonsense. Who is this Teacher anyway? Strong?","TWN":"我對這方面不太瞭解……他是做什麼的？很強嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"내가 아는 한 제일 강한 사람이야.","JPN":"私が知る限り、一番強い人よ。","ENG":"As far as I know, Teacher is the strongest person there is.","TWN":"是我認識的人裡面最強的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자, 자. 두 사람, 개인적인 질문은 그만.","JPN":"さあ、二人とも。個人的な質問はそこまでよ。","ENG":"Alright, you two. Enough with the personal questions.","TWN":"好了，好了，妳們兩個，私人問題就到此為止吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"가은 양. 여기 에블린 언니의 특제 초콜릿이야.","JPN":"ユキさん。これはエヴリンお姉さんの特製チョコレートよ。","ENG":"Gaeun. Try my special chocolate here.","TWN":"嘉恩小姐，這是伊芙琳姐姐的特製巧克力。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"한입만 먹어도 두려움이 사라진단다.","JPN":"一口食べるだけで何も恐れなくなるわ。","ENG":"Just one bite will make your fears subside.","TWN":"吃一口就能消除妳的恐懼。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"고맙습니다. 잘 먹을게요.","JPN":"ありがとうございます。いただきます。","ENG":"Thank you. You're very kind.","TWN":"謝謝妳，我會好好享用的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자, 받아. 이건 부끄러움을 잊게 만들어 주는 드레스야.","JPN":"ほら、受け取れ。これは恥じらいを忘れさせるドレスだ。","ENG":"Here, take this. This dress will make your shyness go away.","TWN":"然後，穿上這個。這是能讓妳忘掉害羞的禮服。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"솔직하게 네 마음을 말할 수 있어.","JPN":"正直に汝の気持ちを言えるだろう。","ENG":"You'll be able to express feelings honestly.","TWN":"可以讓妳坦率地說出自己的心聲。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어? 이거 저번에 관리국에서 운 좋게 낙찰 받은 물건 아냐?","JPN":"あれ？　これって前に管理局で運よく落札した物じゃないの？","ENG":"Huh? Didn't we get this at an auction from the Administration?","TWN":"咦？那不是上次在管理局幸運得標的東西嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"저주를 걸어서 카페 벌칙용으로 쓰겠다더니......","JPN":"呪いをかけてカフェの罰ゲーム用に使うって言ってなかったっけ……","ENG":"I thought you were going to put a curse on it and use it to prank terrible customers...","TWN":"說是下了詛咒，要當作咖啡廳裡的懲罰用道具……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"시, 시끄러워! 저주건 뭐건 목표만 달성하면 되잖아!","JPN":"う、うるさい！　呪いも何も、目標さえ達成すればいいだろ！","ENG":"Sh-shut up! Who cares what it was originally for, as long as it gets the job done!","TWN":"吵，吵死了！管它詛咒不詛咒的，只要能達成目的不就行了！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"부끄러운 의상...... 하지만 선생님을 위해서라면......","JPN":"恥ずかしい衣装……でも先生のためなら……","ENG":"This seems a bit gaudy... But if it's for Teacher...","TWN":"好令人害羞的衣服……但如果是為了老師的話……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자, 이제 됐지? 또 괜한 손님 오기 전에 얼른 가게 문 닫을 준비 하자.","JPN":"さ、もういいな？　また変な客が来る前に閉店の準備をしよう。","ENG":"There. Satisfied? Now let's close shop before we get another customer.","TWN":"現在可以了吧？那在其他多餘的客人上門之前，趕快準備打烊吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 모처럼 마녀다운 일이잖아. 자랑스러워해도 될 텐데.","JPN":"ふふっ。せっかく魔女らしいことをしたんだから。誇らしく思ってもいいのに。","ENG":"Heh heh. But this is what witches are supposed to do. I think you can take a little more pride in this.","TWN":"呵呵，難得做了件魔女的本職工作呢，妳可以感到驕傲喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"저기, 기왕 갈아입는 김에 이 구두는 어때?","JPN":"君、着替えるついでにこの靴はどう？","ENG":"Hey, if you're going to change your clothes anyway, why don't you try on these shoes?","TWN":"那個，脫都脫了，要不要順便再換雙鞋？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"창고에서 가져 온 거지만 꽤 새것 같다구? 잘 어울릴 것 같은데?","JPN":"倉庫から持ってきたんだけど、新品に見えるでしょ？　よく似合いそうだけど？","ENG":"I dug them up from the storage, but they're as good as new! I bet they'll go well with your outfit.","TWN":"雖然是在倉庫裡拿的，但看起來還很新吧？應該很適合妳喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"고마워. 신으니까 어쩐지 가슴이 두근거려.","JPN":"ありがとう。履いたらなんだか胸がドキドキしてきた。","ENG":"I appreciate it. Somehow it's making my heart all fluttery.","TWN":"謝謝……穿上後總覺得心臟跳得好快喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗, 그럼 나도! 저번에 청소하다 찾은 티아라인데 잘 어울릴 거 같아요!","JPN":"あっ、じゃあ私も！　この前掃除中に見つけたティアラですが、これもよく似合いそうです！","ENG":"Oh, then I've got one too! I found this tiara while cleaning the other day. I think it'll look perfect on you!","TWN":"啊，那我也來！這是我上次打掃時找到的頭飾，肯定也很適合妳！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"고마워. 쓰니까 어쩐지 머리가......","JPN":"ありがとう。つけたらなぜか頭が……","ENG":"Thanks. It's making my head feel...","TWN":"謝謝……戴上了總覺得頭有點暈……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후훗......","JPN":"ふふっ……","ENG":"Heh heh...","TWN":"呵呵……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어......? 손님, 괜찮아요?","JPN":"え……？　お客さん、大丈夫ですか？","ENG":"Huh? A-are you okay?","TWN":"呃……？客人，妳沒事嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"그럼요. 막 들뜨고 가슴이 울렁거리는 게 그 어느 때보다 괜찮은 것 같아요.","JPN":"ええ。心が浮き立って胸がざわつくのが、いつにも増して気持ちがいいです。","ENG":"Of course. My heart is racing like crazy but I feel better than ever.","TWN":"當然了。沒有比這種興奮又心跳不已的感覺更好了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다행이다~ 또 실수해 버렸나 했는데~","JPN":"よかった～また失敗したと思った～。","ENG":"Phew, thank goodness. I thought I messed up again.","TWN":"好險～我還以為又搞砸了呢～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"고마워요, 다들. 선생님을 향한 제 사랑을 응원해 줘서.","JPN":"ありがとう、みんな。先生への私の愛を応援してくれて。","ENG":"Thank you, everyone. Thanks for cheering on my love for Teacher.","TWN":"謝謝大家，謝謝大家支持我對老師的愛。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"선생님께서도...... 제가 찾아오기만을 애타게 기다리고 계시겠죠.","JPN":"先生もきっと……私が訪ねてくることを心待ちにしていることでしょう。","ENG":"I'm sure... Teacher's longing for me to come back.","TWN":"老師也……肯定正焦急地等待我的到來吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"베리베리 큐♥ 가은, 오늘 방송은 선생님과 초코처럼 달콤한 사랑 나누기랍니다♥","JPN":"ベリーベリー。キュー♥　ユキ、今日の放送は先生とチョコのように甘い愛の分かち合いです♥","ENG":"Berry Berry Cue! ♥ This is Gaeun! Today's episode will be on my chocolate sweet romance with my Teacher! ♥","TWN":"莓果莓果～♥嘉恩，今天的直播是分享我和老師之間，像巧克力一樣甜蜜的愛情哟♥"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......방금 뭐야? 쟤 맛이 갔는데?","JPN":"……おい、さっきの何だ？　正気じゃないぞ？","ENG":"What the heck was that? She's completely bonkers!","TWN":"……剛剛那是什麼？那孩子好像變了個人一樣？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나, 잉그리드. 두 사람 방금 저 손님에게 뭐 주지 않았어?","JPN":"ユナ、イングリッド。二人ともさっき、あのお客さんに何か渡さなかった？","ENG":"Yuna, Ingrid. Didn't you two just give her something?","TWN":"尤娜，英格麗，妳們兩個是不是給了那位客人什麼東西？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗, 그게 창고에서 찾은 티아라가 예뻐 보여서......","JPN":"あっ、それが倉庫で見つけたティアラが綺麗だったから……","ENG":"Oh, I thought the tiara I found in the storage was pretty...","TWN":"啊，我只是覺得倉庫裡找到的頭飾很漂亮……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나, 나도 그냥 잘 어울릴 것 같아서 창고에 있던 구두만 줬을 뿐이라구.","JPN":"わ、私もよく似合いそうだと思って、倉庫にあった靴を渡しただけよ。","ENG":"A-and I just thought those shoes from the storage would look great on her as well.","TWN":"我、我也只是覺得那雙鞋會很適合那位客人，所以才給她的啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"잡념을 잊게 만드는 티아라에 기분을 고양시키는 구두네.","JPN":"雑念を忘れさせるティアラに、気分を高揚させる靴だな。","ENG":"That tiara makes you forget about any distractions, while the shoes uplift your mood.","TWN":"能消除雜念的頭飾，加上能讓人情緒高漲的鞋子。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 좋은 거 아냐?","JPN":"だったらいいんじゃないの？","ENG":"That's a good thing, isn't it?","TWN":"那不是很好嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아야야야! 플루토, 그만해! 두 개! 정어리 두 개!","JPN":"イタタタ！　プルートー、やめて！　二つ！　イワシ二つあげるから！","ENG":"Ow! Pluto, stop it! I'll give you two! Two cans of tuna!","TWN":"呀啊啊啊！布魯托，STOP！兩罐！兩罐沙丁魚！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자기 마음에 솔직해지고, 두려움도 모르는 상태인 데다가 잡념까지 사라졌어.","JPN":"自分の気持ちに素直になって、恐れも知らないうえに雑念まで消えた。","ENG":"She's become honest about her feelings and fearless. And now all her distractions are gone.","TWN":"內心變得坦率，然後在無所畏懼的狀態下，連雜念都消失了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그 상태로 기분이 들뜨면 사람이 어떻게 되는 줄 알아?","JPN":"その状態で気分まで高揚したら人がどうなるのかわかるか？","ENG":"You know what happens when you boost someone's mood on top of all that?","TWN":"如果在這種情況下情緒高漲，妳們知道會發生什麼事情嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"어떻게 되는데?","JPN":"どうなるの？","ENG":"What?","TWN":"什麼事？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"눈에 뵈는 게 없어져.","JPN":"我を忘れてしまうんだ。","ENG":"She becomes unstoppable.","TWN":"她的眼睛會看不見任何東西。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐, 효력은 길어 봐야 30분도 안 되려나. 큰 사고만 안 나면 좋겠는데.","JPN":"まあ、効果は長くて30分くらいだがな。大事に至らなきゃいいのだが。","ENG":"Well, I guess the spell will last no more than half an hour. Hopefully it won't end up in disaster.","TWN":"不過嘛，效果再長也只會持續30分鐘，不要出什麼大事就好了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래? 지금이라도 뺏어 와야 할까?","JPN":"そうなの？　今からでも取り返したほうがいい？","ENG":"Really? Should we go get the items back before it's too late?","TWN":"是嗎？我們現在不用去把東西搶回來嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐...... 카운터였잖아. 몸살 좀 앓는 정도로 끝날 거야. 그리 걱정할 거 없어.","JPN":"まあ……カウンターだからな。少し体調を崩すくらいで済むだろう。そんなに心配することはない。","ENG":"Well... She's a Counter. She'll just feel a little sick afterwards, that's all. Nothing to worry about.","TWN":"這個嘛……她不是制裁者嗎？他只會稍微感到疲憊，然後就結束了吧，不需要那麼擔心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아니, 그 선생님이란 사람 말이야.","JPN":"いや、心配なのはその先生って人のことよ。","ENG":"I'm more worried about that Teacher she was talking about.","TWN":"不，我是擔心那位老師。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마법이 풀리기 전까지 버틸 수 있으려나 모르겠네. 후훗.","JPN":"魔法が解けるまで耐えられるかわからないわね。ふふっ。","ENG":"I wonder if this person will manage to last until the spell wears off. Heh heh.","TWN":"不知道他能不能撐到魔法失效為止呢，呵呵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"며칠 전 일은 하나 씨에게 보고 받았습니다.","JPN":"数日前のことはスズカさんに報告を受けました。","ENG":"Hana briefed me about what happened a few days ago.","TWN":"前幾天的事情，我已經收到金荷娜小姐的報告了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방송인과도 알고 계시다니 발이 참 넓으시네요.","JPN":"ストリーマーとも知り合いだなんて、顔が広いようですね。","ENG":"You sure get around a lot, getting in touch with people in the entertainment industry too.","TWN":"沒想到您竟然連直播主都認識，人脈真廣呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다음에는 누군가요? 그림자?","JPN":"次は誰ですか？　シャドウ？","ENG":"So what next? A shadow?","TWN":"下一個是誰？暗影？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"농담 말게. 나도 꽤 당황스러웠어.","JPN":"冗談じゃない。私もかなり驚いたんだ。","ENG":"Don't even joke about it. It was all very startling for me too.","TWN":"不要開玩笑了，我也很尷尬啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"지원금 좀 받아 보려고 시작한 방송 협찬 건이 이런 식으로 틀어질 수가 있나......","JPN":"補助金目当てに放送のスポンサーを引き受けたのに、こんな形でこじれるとは……","ENG":"I was just trying to get some sponsors on board... I never knew things would go awry like that.","TWN":"當初我也只是為了拿點支援金，才開始贊助直播的，為什麼事情會變成這樣……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"슬슬 본모습으로 활동하시라는 하늘의 계시 아닐까요?","JPN":"そろそろ元の姿で活動しなさいという天の啓示ではないでしょうか？","ENG":"Maybe it's a sign that you should just unveil who you really are again?","TWN":"這該不會是要您現出真身，來自上天的啟示吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래도 감이 좋은 아이네요. 변조음을 잔뜩 넣은 목소리를 듣고 알아차리다니.","JPN":"でも勘が良い子なんですね。エフェクトで変調された声に気付くなんて。","ENG":"Anyway, she's a pretty sharp kid. She recognized your voice even with all the modulation.","TWN":"不過那孩子的直覺真準呢，居然能透過變調的聲音認出您。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"어릴 적에는 앞을 제대로 못 보는 대신에 청각이나 촉감이 굉장히 좋았으니까.","JPN":"幼い頃は前がよく見えなかったからな。その代わり聴覚や触覚がかなり鋭かったんだ。","ENG":"Her sense of hearing and touch were very well developed when her sight was limited during her childhood.","TWN":"因為她小時候視力不好，相對的，聽覺和觸覺就很敏銳。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래도 한 번에 알아본 건 좀 놀랍긴 하군.","JPN":"それでも一度でわかったのは、さすがに驚いたな。","ENG":"Still, I'm pretty surprised that she recognized me so quickly.","TWN":"但我還是很驚訝她能一下子就認出來。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"비상. 비상. 사옥에 침입자가 감지되었습니다. 시큐리티 시스템을 기동합니다.","JPN":"非常事態発生。非常事態発生。社屋に侵入者が感知されました。セキュリティシステムを起動します。","ENG":"Alert. Alert. Infiltration detected. Activating security system.","TWN":"緊急情況，緊急情況。偵測到公司大樓出現入侵者，保全系統啟動。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"뭐야, 또 무슨 일이지?","JPN":"えっ、今度は何事だ？","ENG":"What now?","TWN":"什麼，又怎麼了？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식 재난은 아니군요. 또 스승님이 경보기를 걷어찬 게 아닐까 싶네요.","JPN":"侵食災害ではないですね。また師匠が警報器を蹴飛ばしたのかもしれません。","ENG":"Well, it's not a Corruption Disaster. Master must have kicked another alarm or something.","TWN":"看起來不是侵蝕災難呢，不會是師父又踢到警報器了吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"경고. 레벨 1 시큐리티 시스템 무력화.","JPN":"警告。レベル1セキュリティシステムの無力化。","ENG":"Warning. Level 1 Security System, neutralized.","TWN":"警告，1級保全系統失效。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"레벨 2 시큐리티 시스템 60% 기능 정지. 레벨 3 시큐리티 시스템 기동합니다.","JPN":"レベル2セキュリティシステム60％機能停止。レベル3セキュリティシステムを起動します。","ENG":"Level 2 Security System at 40%. Activating Level 3 Security System.","TWN":"2級保全系統60%機能停止，3級保全系統啟動。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"레벨 3......?","JPN":"レベル3……？","ENG":"Level 3?","TWN":"3級……？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님이 심각하게 화가 났거나, 경쟁사에서 자객이라도 보낸 모양이군요.","JPN":"師匠がものすごく怒ったか、ライバル会社が刺客でも送り込んだみたいですね。","ENG":"Okay, now Master is super angry... Or one of our competitors sent an assassin.","TWN":"看來不是師父在發飆，就是競爭對手派來的刺客吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금이라도 도망치시는 게 낫지 않을까요?","JPN":"今からでも逃げたほうがいいんじゃないですか？","ENG":"Perhaps we should run while we still can?","TWN":"現在逃跑會不會比較好？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"으음. 그 전에 일단 침입자를 화면에 표시해 보게.","JPN":"うむ。その前にまず侵入者を画面に映してみてくれ。","ENG":"Hmm. Why don't we see who this infiltrator is on the screen first?","TWN":"嗯，在這之前，先讓我看看入侵者是誰。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Sure thing.","TWN":"知道了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 아이는......","JPN":"この子は……","ENG":"That kid...","TWN":"這孩子是……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후훗, 선생님. 부끄러워서 숨어 계신 건가요?","JPN":"ふふっ、先生。照れて隠れているんですか？","ENG":"Hah hah, Teacher? Peekaboo! Are you feeling shy?","TWN":"呵呵，老師……是因為太害羞所以躲起來了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"아니면...... 또 그때처럼 나쁜 사람들 때문에 피해 계시나요?","JPN":"それとも……またあの時みたいに悪い人たちのせいで身を潜めているんですか？","ENG":"Or... Are there baddies like the last time? Are you hiding from them?","TWN":"還是說……又像那時候一樣，因為有壞人所以躲起來了？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"하지만 이제 걱정하지 마세요. 선생님의 가은이가 이렇게 찾아가고 있으니까요.","JPN":"でももう心配しないでください。こうして先生のユキが来ましたから。","ENG":"But don't you worry anymore. Your very own Gaeun is coming to find you.","TWN":"不過，現在您不用再擔心了，因為嘉恩馬上就要回到老師身邊了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"이제...... 두 번 다시 헤어지지 않겠어요.","JPN":"もう……二度と別れることはありません。","ENG":"Never again... will I let anything come between us.","TWN":"現在……我們再也不會分開了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"선생님을 괴롭히는 것들은 제가 모두 없애 드릴게요.","JPN":"先生を苦しめるものは私が全部消してあげますね。","ENG":"I'll get rid of anything or anyone that bothers you.","TWN":"所有想要妨礙老師的壞人，就讓我來消滅他們吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>레벨 4 시퀀스 준비 중. 요인의 대피를 권고합니다.</color>","JPN":"<color=#ffd34c>レベル4シークエンス準備中。要人の避難を勧告します。</color>","ENG":"<color=#ffd34c>Preparing Level 4 sequence. V.I.P. evacuation recommended.</color>","TWN":"<color=#ffd34c>準備啟動4級保全系統。建議相關人員避難。</color>"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"자, 선생님. 어서 나와서 잘했다고 머리를 쓰다듬어 주세요.","JPN":"さあ、先生。早く出てきて、よくやったねと頭をなでてください。","ENG":"Come on, Teacher. Come on out and pat me on the head.","TWN":"來吧，老師，快出來誇獎我，摸摸我的頭吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"제 몸도, 마음도 엉망진창으로 녹아 내릴 만큼...... 후훗♥","JPN":"私の身も心もめちゃくちゃに溶けてしまうくらいに……ふふっ♥","ENG":"I want to feel your affection wash over me... body and soul... Teehee ♥","TWN":"讓我的身體，我的心靈全都融化……呵呵♥"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 어린 시절 만났을 때 무슨 짓을 했던 겁니까?","JPN":"幼い頃に出会った時、いったい何をしたんですか？","ENG":"What the heck did you do to the kid when she was a child?!","TWN":"您到底在她小時候對她做了什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"아니, 그게...... 나도 잘 모르겠는데......","JPN":"いや、それが……私にもよくわからない……","ENG":"Well, I... I have no idea either...","TWN":"不，這個……我也不知道啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그, 그래도 별일 없겠지. 겉으로는 살벌해 보여도 속은 순진한 아이일 텐데......","JPN":"まあでも、大事にはならないだろう。恐ろしいように見えても、中身は純粋な子供だから……","ENG":"I-I'm sure everything will be fine. She may appear dangerous, but she's still an innocent kid inside...","TWN":"不、不過不要緊。雖然她表面上看起來殺氣騰騰，但內心卻是個天真無邪的好孩子……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 보기엔 외딴 통나무집에 감금해 두고 평생 머리만 쓰다듬으라고 할 것 같군요.","JPN":"私が見た感じだと、人里離れた丸太小屋に閉じ込めて、一生頭をなでさせそうですね。","ENG":"From the looks of it, she'll probably keep you locked up in a remote cottage and make you pat her head for the rest of your life.","TWN":"在我看來，您似乎要被監禁在遠離塵世的小木屋，一輩子只能摸她的頭了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그건...... 조금 곤란하겠군.","JPN":"それは……ちょっと困るな。","ENG":"Well... That could be a problem.","TWN":"這……這我就有點困擾了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 제가 가겠습니다. 그동안 사장실에 꼭 숨어 있도록 하세요.","JPN":"今すぐ私が行きます。それまで社長室にしっかり隠れていてください。","ENG":"I'll go take care of this right now. In the mean time, stay hidden in your office.","TWN":"我馬上就過去。這段時間請您好好躲在老闆辦公室。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"선생님~♥","JPN":"先生～♥","ENG":"Oh, Teacher ♥","TWN":"老師～♥"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"선생님의 가은이가 왔어요~","JPN":"先生のユキが来ましたよ～。","ENG":"Your Gaeun is here.","TWN":"老師的嘉恩來了喔～"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"응? 선생님과 저의 만남을 방해하는 문짝이 있네요?","JPN":"うん？　先生と私の再会を邪魔するドアがありますね？","ENG":"Huh? There's a door getting in the way of our lovely reunion!","TWN":"嗯？有扇妨礙我和老師見面的門呢。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"이런 나쁜 문짝은 사랑과 마법의 힘으로 벌을 줘야겠죠?","JPN":"こんな悪いドアは愛と魔法の力で懲らしめてあげないとダメですね？","ENG":"A naughty door like this ought to be punished with my spell of love!","TWN":"這種壞門，就應該用愛之魔法給予懲罰吧？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"주문을 외워 볼게요~ 리리컬~ 매지컬~","JPN":"呪文を唱えましょう～リリカル～マジカル～。","ENG":"Let me incant the spell... Lyrical... Magical...","TWN":"讓我來想想咒語是什麼～抒情～魔法～"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"다이너마이트!","JPN":"ダイナマイト！","ENG":"Dynamite!","TWN":"炸裂！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_18"},{"id":"L28_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"저거 분명 폐기된 함선용 장갑판을 가져와서 달아둔 건데......","JPN":"あれは確か、破棄された艦船用の装甲板を集めて取り付けたものだが……","ENG":"That door was fitted with armor from a decommissioned warship...","TWN":"那是用廢棄的艦船裝甲板做的牆壁啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"저렇게 허망하게 날아가도 되는 건가?","JPN":"あんなに虚しく吹き飛ばされてもいいのか？","ENG":"How could it get blown away so easily?","TWN":"竟然那麼輕易地就被打飛了？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후훗...... 이런 얇은 장막으로는 선생님과 저의 사이를 갈라놓을 수 없는 걸요.","JPN":"ふふっ……こんなに弱い壁では、先生と私の仲を引き裂くことはできないんです。","ENG":"Heh heh... A flimsy door like this couldn't possibly stand in the way of my reunion with you, Teacher.","TWN":"呵呵……這種淺薄的隔閡是無法分開我和老師的。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮으십니까? 사장님!","JPN":"大丈夫ですか？　社長！","ENG":"Are you okay? Boss!","TWN":"您沒事嗎？老闆！"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L35_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"어머, 이건 누구죠?","JPN":"あら、こちらは誰ですか？","ENG":"Oh my, and who's this now?","TWN":"哎呀，這是誰啊？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후후훗, 역시 제가 없는 동안 선생님께 꼬리 치는 여우들이 잔뜩 달라붙었네요.","JPN":"ふふふっ、やっぱり私がいない間に、先生を誘惑するキツネたちがくっついてたんですね。","ENG":"Hah hah, looks like some naughty vixens thought they'd have a chance with you without me around.","TWN":"呵呵呵，果然我不在的時候，有很多纏上老師的狐狸精呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"하지만 곤란해요, 선생님 곁에 있어야 하는 사람은 저 혼자로 충분하거든요.","JPN":"でも困りますよ、先生の隣にいるべき人は私一人で十分なんです。","ENG":"But this won't do at all. There can only be one lady next to you, Teacher.","TWN":"不過這真是困擾呢。陪在老師旁邊的，只要有我一個人就夠了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"선생님의 쓰담쓰담은 제 거에요. 당신 같은 여우에게는 양보 못해.","JPN":"先生のなでなでは私のものです。あなたみたいなキツネには絶対譲れない。","ENG":"Only I get to get my head patted by you, Teacher. Not some vixen like this!","TWN":"老師的摸摸頭只屬於我，我是不會讓給妳這隻狐狸精的。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"어...... 혹시 자네도 내가 쓰다듬어 주길 바라고 있었나?","JPN":"え……ひょっとして君も私になでてほしいと思っていたのか？","ENG":"Um... Did you want me to pat your head, by any chance?","TWN":"呃……妳該不會也想被我摸摸頭吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 그 손 치우시죠. 팔째로 날아가기 싫으시면요.","JPN":"今すぐその手を離してください。腕ごと吹き飛ばされたくなかったら。","ENG":"Take your stinking hand off me. If you don't want me to blow off your entire arm.","TWN":"立刻把你的手拿開，如果你不想少條手臂的話。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"걱정하지 마세요, 선생님. 이제부터는 제가 안전하게 지켜 드릴게요.","JPN":"心配しないでください、先生。これからは私が安全にお守りしますからね。","ENG":"Don't worry, Teacher. I'll keep you safe from now on.","TWN":"不要擔心，老師。從現在開始，我會好好保護您的。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"평~ 생~♥","JPN":"一生～♥","ENG":"Forever! ♥","TWN":"一～輩～子～♥"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......시, 식은땀이 흐르는 건 오랜만이군.","JPN":"……ひ、冷や汗をかくなんて久しぶりだな。","ENG":"I-it's been a while since I've been this nervous.","TWN":"……好、好久沒流這麼多冷汗了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신도 참 죄 많은 사람이로군요.","JPN":"あなたも本当に罪深い人ですね。","ENG":"You sure do have a lot of skeletons in your closet.","TWN":"您可真是個罪孽深重的人啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"자, 어서 제게로 와 주세요.","JPN":"ほら、早く私のほうに来てください。","ENG":"Now, come to me.","TWN":"來吧，請快點到我身邊來吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"저를 꼭 끌어안아서 그 따뜻한 체온도, 부드러운 손길도, 전부 느낄 수 있게......♥","JPN":"ぎゅっと抱きしめて温かい体温も、優しい手つきも、全部感じられるように……♥","ENG":"Hold me tight so I can feel your warm embrace, your loving touch, all of it... ♥","TWN":"緊緊抱住我，讓我感受您的體溫，您柔軟的手，還有您的全部……♥"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일단 뒤로 물러서시죠. 제가 막겠습니다.","JPN":"とりあえず後ろに下がっていてください。私が止めます。","ENG":"Why don't you get behind me for now. I'll fend her off.","TWN":"您先退後，我來擋住她。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"아니, 잠깐 기다려 주게.","JPN":"いや、ちょっと待ってくれ。","ENG":"No, hang on a second.","TWN":"不，等等。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"영문은 모르겠지만...... 저 아이가 저렇게까지 된 건 나 때문이야.","JPN":"理由はわからないが……あの子があんなふうになったのは私のせいだ。","ENG":"I don't know how it's come to this... But I'm responsible for her being this way.","TWN":"雖然不知道事情的起因……但那孩子會變成那樣，都是我的錯。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그러니 내가 어떻게든 달래 봐야지.","JPN":"だから私がどうにかしてでもなだめないと。","ENG":"So I should try to calm her down somehow.","TWN":"所以我得想辦法去安撫她。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이미 눈에 뵈는 게 없는 상태입니다. 가능하다고 생각하시나요?","JPN":"すでに理性を失っている状態です。それが可能だと思いますか？","ENG":"She's already unstoppable. Do you think it's really possible?","TWN":"她已經被某種東西蒙蔽了雙眼，您覺得有可能安撫她嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"가능하길 바라야지.","JPN":"可能であることを願わないとな。","ENG":"I hope so.","TWN":"希望可以吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후훗, 역시 선생님...... 여우들이 저희 사이를 방해해도 제 진심을 알아 주시네요.","JPN":"ふふっ、やっぱり先生……キツネたちが邪魔しても、私の気持ちをわかってくれるんですね。","ENG":"Hah hah, I knew I could count on you, Teacher... Please accept my true feelings for you, no matter how much those vixens try to get in our way.","TWN":"呵呵，不愧是老師……即使有狐狸精阻礙了我們，您還是知道我的心意呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래, 가은 양. 머리를 쓰다듬어 달라고 했지.","JPN":"ああ、ユキさん。頭をなでてほしいと言ったな。","ENG":"Yes, Gaeun. So you wanted me to pat you on the head.","TWN":"是啊，嘉恩小姐，妳想讓我摸摸頭是吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"원하는 대로 해 주겠네.","JPN":"望みどおりにしてやろう。","ENG":"I'll do as you wish.","TWN":"那就如妳所願吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"......아아, 그래요. 이 손길...... 선생님의 손길이에요......♥","JPN":"……ああ、そう。この手つき……先生の手で間違いない……♥","ENG":"Ah... yes... That touch... I've been longing for this, Teacher... ♥","TWN":"……啊啊，沒錯。這隻手……是老師的手……♥"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"좋아해요, 정말 정말 좋아해요, 좋아해요, 좋아해요...... 선생님♥ 이 순간이 오기만을 기다렸어......♥","JPN":"好きです、本当に本当に好きです、好きです、好きです……先生♥　この瞬間だけを待ってた……♥","ENG":"I like you so much... Oh, so, so very much... I've been waiting so long for this moment...♥","TWN":"喜歡，真的好喜歡，喜歡，喜歡……老師♥我等這一刻等了好久……♥"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......이제 마음이 좀 후련해졌나?","JPN":"……これでもう気持ちがスッキリしたか？","ENG":"Feeling better?","TWN":"……心情好一點了嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"으음...... 정말정말 행복하지만......","JPN":"うーん……本当に本当に幸せだけど……","ENG":"Um... I'm really, really happy right now...","TWN":"嗯……我真的真的好幸福，但是……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"아뇨. 선생님의 손길을 느끼니 더는 참을 수가 없어졌어요.","JPN":"いいえ。先生になでてもらったら、余計我慢できなくなりました。","ENG":"But no. Now that I've felt your touch, I can't hold myself back anymore.","TWN":"沒有。感受到老師的手，我再也忍不住了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"좀 더...... 온몸으로 느끼고 싶어져요♥","JPN":"もっと……全身で感じてみたいんです♥","ENG":"I want to feel your touch... all over my body now ♥","TWN":"想要……更加用全身感受一下♥"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......큰일이군요. 이미 충분히 위험한 상태입니다.","JPN":"……大変ですね。もう十分危険な状態です。","ENG":"Uh-oh... She's already dangerous enough as it is.","TWN":"……真糟糕呢，已經變成十分危險的狀態了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"도리어 자극한 셈이 됐나...... 곤란하군.","JPN":"かえって刺激してしまったか……困ったな。","ENG":"Did I only set her off even more? This can't be good.","TWN":"反而刺激到她了嗎……這下難辦了。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"후훗, 알았다~ 다른 여우들의 시선이 불쾌하신 거죠?","JPN":"ふふっ、わかった～。他のキツネたちの視線が気になるんですね？","ENG":"Oh, I know what it is. You're uncomfortable about the other vixens watching, right?","TWN":"呵呵，我知道了～您在意其他狐狸精的視線對吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"괜찮아요. 저희 둘이서 오붓하게 지낼 수 있는 곳으로 모셔다 드릴게요, 선생님.","JPN":"大丈夫ですよ。二人だけで静かに過ごせる場所にお連れしますからね、先生。","ENG":"Don't worry. I'll take you somewhere where we can be together, just the two of us.","TWN":"沒關係，那就去一個只有我們兩個人的平靜地方吧，老師。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"그곳에선 제가 하나부터 열까지 곁에서 챙겨 드리고...... 기쁘게 해 드릴 테니까요.","JPN":"そこでは私が何から何までそばでお世話して……喜ばせてあげますから。","ENG":"I'll tend to your every need there... and keep you satisfied.","TWN":"我會把您照顧得無微不至……讓您快快樂樂沒煩惱。"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"제 모든 걸 바쳐서라도......","JPN":"私のすべてを捧げてでも……","ENG":"Even if I have to sacrifice everything...","TWN":"就算要把我的一切都奉獻給您……"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GAEUN_HB_VAL_BLACK","text":{"KOREA":"영원히......♥","JPN":"永遠に……♥","ENG":"Forever... ♥","TWN":"永遠……♥"},"stage":{"bg":"OFFICE_TOP","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_BLACK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"......어?","JPN":"……え？","ENG":"Huh?","TWN":"……咦？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"응......?","JPN":"うん……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"나......","JPN":"私……","ENG":"What...","TWN":"我……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"왜...... 이런 곳에......? 게다가 이 부끄러운 복장은 대체......?","JPN":"どうして……こんな所に……？　それに、この恥ずかしい服装は何なの……？","ENG":"What am I... doing here? And what's with this embarrassing outfit?","TWN":"我為什麼……在這裡……？這羞恥的衣服，到底是……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"저, 정신이 들었나. 어떻게 된 일인지는 모르겠지만 다행이야.","JPN":"き、気がついたか。どういうことなのかわからないが、本当によかったよ。","ENG":"H-have you come to your senses? I'm not sure what happened, but thank goodness.","TWN":"妳、妳終於清醒了。雖然不知道發生了什麼，但真是太好了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"그 목소리...... 설마, 선생...... 님?","JPN":"この声……まさか、先……生？","ENG":"That voice... Is it you... Teacher?","TWN":"這聲音是……難道是老……老師？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"아, 안 돼. 이런 부끄러운 모습으로 뵙고 싶지는 않았...... 는데......","JPN":"い、いや……こんな恥ずかしい姿でお会いしたくなかった……のに……","ENG":"N-no... I'm so embarrassed... This wasn't what I had in mind...","TWN":"不、不要。我不想用這麼羞恥的模樣……來見您……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......기절했군요. 정신을 잃을 만큼 부끄러웠나 보네요.","JPN":"……気絶しましたね。気を失うくらい恥ずかしかったようです。","ENG":"She passed out. I guess she was embarrassed enough to pass out.","TWN":"……昏過去了。看來是害羞到昏過去了呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"십년감수했군. 일단은 보호자에게 연락해 주겠나?","JPN":"寿命が縮んだよ。とりあえず保護者に連絡してくれるか？","ENG":"That was close. Could you get in touch with her legal guardian for now?","TWN":"我覺得我的壽命少了十年。總之，妳能聯絡到監護人嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"병원 쪽도 수소문해서 정밀검사도 받을 수 있게 해 주게.","JPN":"あと病院を手配して、精密検査も受けられるようにしてくれ。","ENG":"And call the hospital and see if she needs to get some tests done as well.","TWN":"同時醫院那邊也聯絡一下，好讓她能接受精密的檢查。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"가벼운 저주...... 그러니까 CRF 쇼크인 것 같은데 혹시 모르니까.","JPN":"軽い呪い……つまりCRFショックのようだが、念のためにな。","ENG":"It seems to be a light curse of some kind... as in a CRF shock. But you never know.","TWN":"輕微的詛咒……這有可能是CRF休克，但以防萬一。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 그런데......","JPN":"わかりました。ですが……","ENG":"Understood. By the way...","TWN":"我知道了。不過……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"음? 뭔가 할말이라도 있나?","JPN":"うん？　何か言いたいことでもあるのか？","ENG":"Hmm? Did you want to say something?","TWN":"嗯？妳有什麼想說的嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 식으로 덮어 봐야 같은 일이 반복될 뿐입니다.","JPN":"こうしてうやむやにしても同じことが繰り返されるだけです。","ENG":"Covering this up will only cause it to happen again, eventually.","TWN":"您要是還想繼續隱瞞下去，只會讓今天的事情再度重演。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"차라리 솔직하게 이야기하시는 건 어떨까요?","JPN":"いっそのこと正直にお話してはどうでしょうか？","ENG":"Why don't you just be honest with her instead?","TWN":"不如直接坦誠相見怎麼樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"농담이겠지? 간신히 평범한 삶을 찾은 아이를 내 곁에 두면 무슨 일이 생길지 알지 않나?","JPN":"冗談だろ？　やっと平凡な日常を取り戻した子を私のそばに置いたらどうなるか、君もわかるじゃないか。","ENG":"You're kidding, right? She just barely managed to get her life back. Who knows what would happen if I let her stay with me?","TWN":"妳在開玩笑吧？這孩子好不容易能過普通生活，妳不知道她跟我在一起會發生什麼事嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇긴 합니다만, 그 아이가 원하는 게 뭔지도 생각해 보시면 좋을 것 같네요.","JPN":"そうですが、あの子が望んでいることが何かを考えてみるといいかもしれません。","ENG":"I understand that, but perhaps you should think about what she wants.","TWN":"話是沒有錯，但是您還是得思考看看，那個孩子要的究竟是什麼。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사람의 마음이란 건 밀어내기만 한다고 능사는 아니니까요.","JPN":"人の心は、突き放せば終わりというわけにもいきませんから。","ENG":"Turning people away doesn't solve everything, especially when it comes to personal feelings.","TWN":"一直拒絕別人的心意可不是什麼好事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};